INSERT INTO public.blog_posts (title, slug, excerpt, content, author_id, is_published, published_at, category, cover_image_url)
VALUES
('Shop4Me Partners with Leading Lagos Markets for Faster Shopping', 'shop4me-partners-lagos-markets', 'Strategic partnerships with Balogun, Computer Village, and Trade Fair markets streamline the shopping experience for thousands of customers.', 'Shop4Me has announced strategic partnerships with major Lagos markets including Balogun Market, Computer Village, and Trade Fair Complex. These partnerships enable our agents to navigate markets more efficiently, access better pricing for customers, and ensure faster order fulfillment. The initiative is part of our commitment to making market shopping accessible to everyone, regardless of their schedule or location. With dedicated agent stations now set up in these markets, average shopping times have been reduced by 40%.', '00000000-0000-0000-0000-000000000000', true, now() - interval '20 days', 'press', NULL),

('Shop4Me Reaches 10,000 Successful Deliveries Milestone', 'shop4me-10000-deliveries', 'A major milestone as Shop4Me completes 10,000 successful deliveries across Lagos and Port Harcourt, with a 98% customer satisfaction rate.', 'Shop4Me is proud to announce that we have successfully completed over 10,000 deliveries since our launch. This milestone reflects the trust our customers place in us and the dedication of our growing network of shopping agents. Our customer satisfaction rate stands at an impressive 98%, with an average delivery time of under 3 hours. We are grateful to every customer, agent, and team member who has contributed to this achievement. As we continue to grow, we remain committed to providing the best personal shopping and delivery service in Nigeria.', '00000000-0000-0000-0000-000000000000', true, now() - interval '15 days', 'press', NULL),

('Shop4Me Introduces Wallet Payment System for Seamless Transactions', 'shop4me-wallet-payment-system', 'New in-app wallet feature allows customers to fund their account and pay for orders instantly, eliminating payment delays.', 'Shop4Me has launched a new wallet payment system that allows customers to pre-fund their accounts and pay for shopping orders instantly. The wallet supports bank transfers, card payments via Paystack, and can be topped up at any time. This feature eliminates the friction of per-order payments and ensures agents can begin shopping immediately upon order acceptance. The wallet also provides detailed transaction history and spending summaries, giving customers full visibility into their shopping expenses.', '00000000-0000-0000-0000-000000000000', true, now() - interval '10 days', 'press', NULL),

('Shop4Me Expands Agent Network with New Training Program', 'shop4me-agent-training-program', 'A comprehensive training initiative equips new agents with market navigation skills, customer service excellence, and efficient delivery practices.', 'Shop4Me has launched an enhanced agent training program designed to maintain our high service standards as we scale. The program covers market navigation techniques, product quality assessment, customer communication best practices, and safe delivery protocols. New agents undergo a rigorous vetting process including background checks and market knowledge assessments before being approved. This investment in our agent network ensures every Shop4Me customer receives consistent, professional service regardless of which agent handles their order.', '00000000-0000-0000-0000-000000000000', true, now() - interval '5 days', 'press', NULL);

